patch:
--- a/comparator_64bit.vhd
+++ b/comparator_64bit.vhd
@@ -6,7 +6,7 @@
   port (a : in std_logic_vector(63 downto 0);
         b : in std_logic_vector(63 downto 0);
         eq : out std_logic);
-  process(a)
+  process(a, b)
   begin
     if a = b then
       eq <= '1';

before_code:
library ieee;
use ieee.std_logic_1164.all;

entity comparator_64bit is
  port (a : in std_logic_vector(63 downto 0);
        b : in std_logic_vector(63 downto 0);
        eq : out std_logic);
end entity comparator_64bit;

architecture rtl of comparator_64bit is
begin
  process(a)
  begin
    if a = b then
      eq <= '1';
    else
      eq <= '0';
    end if;
  end process;
end architecture rtl;

after_code:
library ieee;
use ieee.std_logic_1164.all;

entity comparator_64bit is
  port (a : in std_logic_vector(63 downto 0);
        b : in std_logic_vector(63 downto 0);
        eq : out std_logic);
end entity comparator_64bit;

architecture rtl of comparator_64bit is
begin
  process(a, b)
  begin
    if a = b then
      eq <= '1';
    else
      eq <= '0';
    end if;
  end process;
end architecture rtl;
